use aiken/collection/dict
use aiken/collection/list
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}
const label_222: ByteArray = #"000de140"
const label_100: ByteArray = #"000643b0"

fn has_cip68_label(name: ByteArray, label: ByteArray) -> Bool {
  bytearray.length(name) >= 4 && bytearray.take(name, 4) == label
}

/// Token name must carry either the (222) or (100) CIP-68 label
fn is_known_label(name: ByteArray) -> Bool {
  has_cip68_label(name, label_222) || has_cip68_label(name, label_100)
}

/// All minted token names must carry a known CIP-68 label
fn all_known_labels(tokens: dict.Dict<ByteArray, Int>) -> Bool {
  list.all(
    dict.to_pairs(tokens),
    fn(p) {
      let Pair(name, _) = p
      is_known_label(name)
    },
  )
}

validator cip68_label_only {
  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let token_count = dict.size(tokens)
    let at_least_one = token_count > 0
    let all_valid_labels = all_known_labels(tokens)
    let no_zero_amounts =
      list.all(
        dict.to_pairs(tokens),
        fn(p) {
          let Pair(name, qty) = p
          is_known_label(name) && qty != 0
        },
      )
    at_least_one && all_valid_labels && no_zero_amounts
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_label_only_empty() {
  all_known_labels(dict.empty)
}

test prop_label_222_accepted(suffix via fuzz.bytearray_between(1, 28)) {
  let name = bytearray.concat(label_222, suffix)
  is_known_label(name)
}

test prop_label_100_accepted(suffix via fuzz.bytearray_between(1, 28)) {
  let name = bytearray.concat(label_100, suffix)
  is_known_label(name)
}

test prop_no_label_rejected(name via fuzz.bytearray_between(4, 32)) {
  let has222 = has_cip68_label(name, label_222)
  let has100 = has_cip68_label(name, label_100)
  if has222 || has100 {
    True
  } else {
    !is_known_label(name)
  }
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// A name shorter than 4 bytes can never carry a valid CIP-68 label prefix,
/// so is_known_label must always return False for such inputs.
test prop_short_name_rejected(
  name via fuzz.bytearray_between(0, 3),
) fail {
  expect is_known_label(name)
}

/// A name whose first 4 bytes are all-zero (#"00000000") is neither label_222
/// (#"000de140") nor label_100 (#"000643b0"), so is_known_label must return False.
test prop_zero_prefix_rejected(
  suffix via fuzz.bytearray_between(0, 28),
) fail {
  let bad_prefix: ByteArray = #"00000000"
  let name = bytearray.concat(bad_prefix, suffix)
  expect is_known_label(name)
}

/// A dict containing a single token whose name has no valid CIP-68 label causes
/// all_known_labels to return False.  We build the name with a zero prefix so
/// it is guaranteed to be 4+ bytes yet match neither label_222 nor label_100.
test prop_all_known_labels_fails_on_bad_name(
  suffix via fuzz.bytearray_between(1, 28),
) fail {
  let bad_prefix: ByteArray = #"00000000"
  let bad_name = bytearray.concat(bad_prefix, suffix)
  let tokens = dict.insert(dict.empty, bad_name, 1, bytearray.compare)
  expect all_known_labels(tokens)
}

/// has_cip68_label must return False when the name is shorter than 4 bytes,
/// regardless of which label is tested.
test prop_has_cip68_label_too_short(
  name via fuzz.bytearray_between(0, 3),
) fail {
  expect has_cip68_label(name, label_222)
}
